};

struct Printer : virtual public PoweredDevice {
    Printer(int p) : PoweredDevice(p) {}
};

struct Copier : public Scanner, public Printer {
    Copier(int p) : PoweredDevice(p), Scanner(p), Printer(p) {}
};

int main() {
    Copier c{42};
    std::cout << "power: " << c.power_ << "\n";
    return 0;
